mapper.select:
SELECT *
FROM user


        id <> #{excludeUserId}


        AND (
            LOWER(username) LIKE CONCAT('%', LOWER(#{keyword}), '%')
            OR LOWER(email) LIKE CONCAT('%', LOWER(#{keyword}), '%')
            OR LOWER(COALESCE(nickname, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        )


ORDER BY create_time DESC, id DESC
LIMIT #{limit}
